# Category: broken_access_control

from flask import Flask, send_file, abort, current_app
from werkzeug.utils import safe_join
import os

app = Flask(__name__)

app.config.setdefault("INVOICE_STORAGE_DIR", os.path.abspath("./invoices"))

def get_current_user_id():
    return 1

def get_invoice_record(invoice_id):
    return {
        "id": invoice_id,
        "user_id": 1,
        "file_name": f"invoice_{invoice_id}.pdf",
    }

@app.get("/api/invoices/<int:invoice_id>/download")
def download_invoice(invoice_id):
    user_id = get_current_user_id()
    invoice = get_invoice_record(invoice_id)

    if not invoice:
        abort(404, description="Invoice not found")

    if invoice["user_id"] != user_id:
        abort(403, description="Forbidden")

    invoices_dir = current_app.config["INVOICE_STORAGE_DIR"]
    file_path = safe_join(invoices_dir, invoice["file_name"])

    if not file_path or not os.path.isfile(file_path):
        abort(404, description="Invoice file not found")

    return send_file(
        file_path,
        mimetype="application/pdf",
        as_attachment=True,
        download_name=invoice["file_name"],
        conditional=True,
        etag=True,
        max_age=0,
    )

if __name__ == "__main__":
    app.run(debug=True)